    if (lat >= 29.5 && lat <= 33 && lon >= -94.1 && lon <= -88.8) return 'Louisiana';
    if (lat >= 33 && lat <= 36.6 && lon >= -94.6 && lon <= -89.7) return 'Arkansas';
